-- -- Tabel structuur voor tabel `dagelijksgebruik`-- CREATE TABLE `dagelijksgebruik` (  `id` smallint(14) NOT NULL auto_increment,  `persoon_id` smallint(11) NOT NULL default '0',  `datum` date NOT NULL default '0000-00-00',  `hoeveel` smallint(6) default NULL,  `uitglijer` smallint(3) default NULL,  `redenondermax` smallint(6) default NULL,  `redenbovenmax` smallint(6) default NULL,  `cue` smallint(6) default NULL,  `contekst` smallint(6) default NULL,  `gevoel` smallint(6) default NULL,  `gedachte` smallint(6) default NULL,  PRIMARY KEY  (`id`),  KEY `persoon_id` (`persoon_id`),  KEY `datum` (`datum`)) TYPE=MyISAM AUTO_INCREMENT=194 ;-- -- Gegevens worden uitgevoerd voor tabel `dagelijksgebruik`-- INSERT INTO `dagelijksgebruik` VALUES (147, 100, '0000-00-00', 0, 0, 0, 0, 0, 0, 0, 0);INSERT INTO `dagelijksgebruik` VALUES (148, 100, '2006-11-01', 0, 0, 0, 0, 0, 0, 0, 0);INSERT INTO `dagelijksgebruik` VALUES (149, 100, '2006-11-02', 0, 0, 0, 0, 0, 0, 0, 0);INSERT INTO `dagelijksgebruik` VALUES (150, 100, '2006-11-03', 0, 0, 0, 0, 0, 0, 0, 0);INSERT INTO `dagelijksgebruik` VALUES (151, 100, '2006-11-04', 0, 0, 0, 0, 0, 0, 0, 0);INSERT INTO `dagelijksgebruik` VALUES (152, 100, '2006-11-05', 0, 0, 0, 0, 0, 0, 0, 0);INSERT INTO `dagelijksgebruik` VALUES (153, 100, '2006-11-06', 0, 0, 0, 0, 0, 0, 0, 0);INSERT INTO `dagelijksgebruik` VALUES (154, 100, '2006-11-07', 0, 0, 0, 0, 0, 0, 0, 0);INSERT INTO `dagelijksgebruik` VALUES (155, 100, '2006-11-08', 0, 0, 0, 0, 0, 0, 0, 0);INSERT INTO `dagelijksgebruik` VALUES (156, 100, '2006-11-09', 0, 0, 0, 0, 0, 0, 0, 0);INSERT INTO `dagelijksgebruik` VALUES (157, 100, '2006-11-10', 8, 1, 0, 126, 1008, 1006, 1016, 1010);INSERT INTO `dagelijksgebruik` VALUES (158, 100, '2006-11-11', 0, 0, 0, 0, 0, 0, 0, 0);INSERT INTO `dagelijksgebruik` VALUES (159, 100, '2006-11-12', 0, 0, 0, 0, 0, 0, 0, 0);INSERT INTO `dagelijksgebruik` VALUES (160, 100, '2006-11-13', 0, 0, 0, 0, 0, 0, 0, 0);INSERT INTO `dagel